const input = $('Called by Agent').first().json;
const response = $input.first().json.content?.[0]?.text || '{}';
const day = input.day || input.parameters?.day || 1;
const clientName = input.client_name || input.parameters?.client_name || input.chatInput || 'Client';
const childName = input.child_name || input.parameters?.child_name || 'Student';
const city = input.city || input.parameters?.city || 'Dubai';

let parsed = {};
try {
  parsed = JSON.parse(response);
} catch (e) {
  parsed = { message: response, channel: 'whatsapp', send_time: '10:00', follow_up_needed: true, next_day: day === 1 ? 3 : day === 3 ? 7 : null };
}

return [{ json: {
  status: 'completed',
  workflow: '11_onboarding_sequence',
  client_name: clientName,
  child_name: childName,
  city,
  onboarding_day: day,
  message: parsed.message || '',
  channel: parsed.channel || 'whatsapp',
  send_time: parsed.send_time || '10:00',
  follow_up_needed: parsed.follow_up_needed !== undefined ? parsed.follow_up_needed : true,
  next_day: parsed.next_day !== undefined ? parsed.next_day : (day === 1 ? 3 : day === 3 ? 7 : null),
  completedAt: new Date().toISOString()
} }];
